import{_ as r,C as a,o as i,c as n,ag as l,E as d,j as e,a as o}from"./chunks/framework._658-eYr.js";const f=JSON.parse('{"title":"Proposals","description":"","frontmatter":{},"headers":[],"relativePath":"guide/proposals.md","filePath":"guide/proposals.md"}'),p={name:"guide/proposals.md"};function c(g,t,h,m,u,w){const s=a("SchemeImage");return i(),n("div",null,[t[0]||(t[0]=l('<h1 id="proposals" tabindex="-1">Proposals <a class="header-anchor" href="#proposals" aria-label="Permalink to &quot;Proposals&quot;">​</a></h1><p>Proposals are AI-scored content ideas that go through a curation workflow before entering the production pipeline. Proposals are <strong>channel-scoped</strong> and available to <strong>premium users</strong> only.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li><strong>Generation</strong> — the <code>proposal-generate</code> NATS worker analyzes trends, channel history, and audience signals to generate 5 scored proposals per run</li><li><strong>Scoring</strong> — each proposal receives a 0-100 score based on weighted criteria (see below)</li><li><strong>Review</strong> — browse proposals sorted by score, with trend signals and timeliness indicators</li><li><strong>Decision</strong> — approve proposals to convert them into ideas, or reject to dismiss</li></ol><p>Proposals appear <strong>under channels</strong> in the sidebar (not as a standalone section).</p><h2 id="proposal-fields" tabindex="-1">Proposal Fields <a class="header-anchor" href="#proposal-fields" aria-label="Permalink to &quot;Proposal Fields&quot;">​</a></h2><p>Each generated proposal includes:</p><ul><li><strong>Title</strong> — the proposed video topic</li><li><strong>Hook</strong> — an attention-grabbing opening line</li><li><strong>Angle</strong> — the unique perspective or framing</li><li><strong>Score</strong> — AI confidence score (0-100)</li><li><strong>Reasoning</strong> — why this topic scored the way it did</li><li><strong>Content gap</strong> — what&#39;s missing in existing coverage of this topic</li><li><strong>Suggested angle</strong> — recommended approach for the channel</li><li><strong>Trend signals</strong> — what data points support this topic</li><li><strong>Timeliness</strong> — how time-sensitive the topic is</li><li><strong>Tags</strong> — topic tags for categorization</li></ul><h2 id="scoring-criteria" tabindex="-1">Scoring Criteria <a class="header-anchor" href="#scoring-criteria" aria-label="Permalink to &quot;Scoring Criteria&quot;">​</a></h2><p>The score (0-100) is a weighted composite:</p><table tabindex="0"><thead><tr><th>Factor</th><th>Weight</th><th>Description</th></tr></thead><tbody><tr><td>Trend momentum</td><td>40%</td><td>How strongly the topic is trending right now</td></tr><tr><td>Content gap</td><td>30%</td><td>How underserved the topic is in existing content</td></tr><tr><td>Topic alignment</td><td>20%</td><td>How well the topic fits the channel&#39;s themes</td></tr><tr><td>Timeliness</td><td>10%</td><td>How time-sensitive the opportunity is</td></tr></tbody></table>',11)),d(s,{name:"proposals-panel",alt:"Proposals Panel"}),t[1]||(t[1]=e("div",{class:"tip custom-block"},[e("p",{class:"custom-block-title"},"TIP"),e("p",null,[o("Proposals require the "),e("code",null,"premium"),o(" Keycloak role (admin auto-qualifies). The "),e("code",null,"proposal-generate"),o(" worker is a fully implemented NATS consumer — not a stub.")])],-1))])}const _=r(p,[["render",c]]);export{f as __pageData,_ as default};
